// inferred-not-tested:主题 CSS link 进本页 head(铁律 2:artifact 自有 document);默认 +esm 含全部语言 → highlightAuto 可用
import hljs from 'https://cdn.jsdelivr.net/npm/highlight.js@11.11.1/+esm';
const link = document.createElement('link'); link.rel = 'stylesheet'; link.href = `https://cdn.jsdelivr.net/npm/highlight.js@11.11.1/styles/${data.theme ?? 'default'}.min.css`; document.head.appendChild(link);
const el = document.getElementById('code'); el.style.maxHeight = '360px'; el.style.overflow = 'auto';
const res = data.language ? hljs.highlight(data.code, { language: data.language, ignoreIllegals: data.ignoreIllegals ?? true }) : hljs.highlightAuto(data.code);
el.innerHTML = `<pre class="hljs"><code>${res.value}</code></pre>`;  // res.value 已转义的高亮 HTML;res.language 是检测/指定到的语言

