import hljs from 'https://cdn.jsdelivr.net/npm/highlight.js@11.11.1/+esm';
const link = document.createElement('link'); link.rel = 'stylesheet'; link.href = `https://cdn.jsdelivr.net/npm/highlight.js@11.11.1/styles/${data.theme ?? 'default'}.min.css`; shadowRoot.appendChild(link);
const el = document.createElement('div'); el.style.maxHeight = '360px'; el.style.overflow = 'auto'; shadowRoot.appendChild(el);
const res = data.language ? hljs.highlight(data.code, { language: data.language, ignoreIllegals: data.ignoreIllegals ?? true }) : hljs.highlightAuto(data.code);
el.innerHTML = `<pre class="hljs"><code>${res.value}</code></pre>`;

